var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......슬슬 도시 경계 바깥이다.","JPN":"……そろそろ都市の境界を越えるところだ。","ENG":"...We're almost clear of the city borders.","TWN":"……差不多到城市範圍外了。"},"stage":{"bg":"MAINSTREAM_113010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다행히 외곽에는 경비 병력이 별로 없었던 모양이야. 길을 막는 놈들은 없군.","JPN":"幸い、外には警備兵力があまり配置されていないようだ。行く手を阻む奴らはいないな。","ENG":"Lucky for us, the defense must be pretty thin on the outskirts. There's no one blocking our path.","TWN":"幸好，週邊似乎沒什麼警備兵力，沒有人擋住去路。"},"stage":{"bg":"MAINSTREAM_113010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"MAINSTREAM_113010","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아까 그 패닉을 일으키던 아가씨는 어떻게 됐지?","JPN":"さっきパニックを起こしていた嬢ちゃんはどうなった？","ENG":"How's the little lady doing? The one who had a panic attack?","TWN":"剛才陷入恐慌的小姐怎麼樣了？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......지금은 좀 진정된 것 같아. 자고 있어.","JPN":"……いまは落ち着いてるみたい。寝てるの。","ENG":"She's doing better... She fell asleep.","TWN":"……現在似乎冷靜下來了，正在睡覺。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다행이군.","JPN":"それは良かった。","ENG":"That's a relief.","TWN":"那就好。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"중화기를 잔뜩 들고 있던데, 그러다가 오발사고라도 나면 곤란하니까.","JPN":"重火器をいっぱい持ってたし、誤射でも起きたら大変だからな。","ENG":"I saw her carrying a bunch of heavy firearms... We wouldn't want her to misfire, right?","TWN":"她還拿著一堆重型武器呢，萬一不小心走火那可麻煩了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 아가씨.","JPN":"おい、嬢ちゃん。","ENG":"Hey, young lady.","TWN":"喂，小姐。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"조금 전부터 인상만 잔뜩 찌푸리고 있는데.......","JPN":"さっきからずっと険しい表情だが……","ENG":"You've been frowning for a while now...","TWN":"妳從剛才開始好像就一直皺著眉頭……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"작전대로 잘 도망쳤잖아? 기쁜 티라도 좀 내는 게 어때?","JPN":"作戦通り、上手く逃げられたじゃないか。嬉しくないのか？","ENG":"Didn't everything go as planned? You could at least pretend to be a li'l more chipper.","TWN":"我們不是按照作戰順利逃脫了嗎？哪怕裝個樣子也好，稍微開心點怎麼樣？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니면 무슨 고민이라도 있나?","JPN":"それとも、何か悩みでもあるのか？","ENG":"Or are you worried about something?","TWN":"還是說妳有什麼煩惱？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨, 궁금한 게 있어.","JPN":"おじさん、私気になることがあるの。","ENG":"I have a question, actually.","TWN":"大叔，有件事我很好奇。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아까 그 괴물 녀석들...... 혹시 예전에도 본 적이 있는 거야?","JPN":"さっきの化け物……もしかして、以前にも見たことあるんじゃない？","ENG":"Those monsters back there... Have you ever seen them before?","TWN":"剛才那些怪物……你之前該不會也有見過吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"처음 본 것치곤 익숙하게 대응하던데......","JPN":"初めて見るわりには、扱い方に慣れてるなと思って……","ENG":"You looked like you knew what you were doing...","TWN":"如果是第一次見到，你對付它們的樣子未免也太熟練了……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......융합체 놈들 말인가?","JPN":"……融合体のことか？","ENG":"You mean those hybriders?","TWN":"……妳是說那些融合體嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"융합체?","JPN":"融合体？","ENG":"Hybrider?","TWN":"融合體？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"인간과 침식체를 인위적으로 융합해서 만든 병사들이지.","JPN":"人間と侵食体を人工的に融合させて作り出した兵士なんだ。","ENG":"Those soldiers were created by artificially fusing humans and C.O.s together.","TWN":"那是用人為的方式將人類和侵蝕體融合在一起，製造出來的士兵。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사람과 침식체를 합친다고? 제정신이야?","JPN":"人間と侵食体を融合？　正気なの！？","ENG":"Combining humans and Corrupted Objects? Are they insane?","TWN":"把人和侵蝕體合體？他們瘋了嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 왜 그런 짓을......?","JPN":"どうしてそんなことを……？","ENG":"Why would they do such a thing...?","TWN":"到底為什麼要做這種事？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"침식체의 육체를 가지고 인간의 장비를 사용하는, 말이 통하는 병사들이지.","JPN":"侵食体の肉体を持ちながら人間の装備を使用する、会話が通じる兵士さ。","ENG":"They have the physical prowess of a C.O. while retaining the ability to communicate and use human equipment.","TWN":"那些士兵有侵蝕體的身體、用著人類的裝備、語言還能互通。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"꽤 매력적인 이야기 아닌가? 가끔은 나도 시술 받고 싶을 정도야.","JPN":"なかなか魅力的な話だろ？　俺も施術を受けたくなるくらいだよ。","ENG":"The perfect soldier, really. Sometimes I almost want to get the procedure done myself.","TWN":"這不是很吸引人嗎？連我有時都會想要接受這個手術呢。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......부작용만 없다면 말이지.","JPN":"……副作用さえ無ければの話だがな。","ENG":"If it weren't for the side effects, that is.","TWN":"……只要沒有副作用的話。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부작용?","JPN":"副作用？","ENG":"Side effects?","TWN":"副作用？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"일반인이 융합체 시술을 성공적으로 끝낼 확률은 아무리 잘 쳐줘도 30% 이하다.","JPN":"一般人が融合体の施術で成功する確率は、どんなに盛っても30％以下だ。","ENG":"The chances of an ordinary person successfully undergoing a hybrider procedure is only 30% at best.","TWN":"一般人接受融合體手術的成功率，不管技術再怎麼好，最多也只有30%。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......적어도 내가 알아낸 정보에 따르면 그렇지.","JPN":"……少なくとも俺が調べた情報だと、そうだな。","ENG":"At least according to my intel...","TWN":"……至少我知道的情報是這樣。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"30%......? 그럼 실패하면 어떻게 되는데......?","JPN":"30％……？　じゃあ、失敗したらどうなるの……？","ENG":"30%......? What happens if the procedure fails...?","TWN":"30%？那失敗的話會怎麼樣？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"글쎄? 어떻게 될 것 같나?","JPN":"さあな、どうなると思う？","ENG":"Well? What do you think?","TWN":"妳說呢？妳覺得會怎麼樣？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"힌트를 주자면, 별로 좋은 꼴이 되진 않아.","JPN":"ヒントをあげるとしたら、あまり良い状態にはならないさ。","ENG":"I'll give you a hint: It's not pretty.","TWN":"給妳些提示吧，不會有什麼好事發生的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"자세한 설명은 의뢰인을 만난 후에 하는 게 좋겠군.","JPN":"詳しい説明は依頼人に会ってからにしよう。","ENG":"I'll tell you more once we get to my client.","TWN":"具體細節還是等見到我的委託人之後再說比較好。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 정도면 놈들의 전파교란지역도 벗어났을 테니 연락을 해 봐야겠어.","JPN":"そろそろ奴らの電波攪乱地域から外れただろうし、連絡してみるか。","ENG":"We should be out of jamming range by now, so I'll give them a call.","TWN":"到這裡，差不多也脫離那些傢伙的電波干擾區域了，我來看看能不能通訊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여기는 콜 사인 스마트 가이. 블랙 버드 응답하라.","JPN":"こちらはコールサイン・スマートガイ。ブラックバード応答せよ。","ENG":"This is Smart Guy. Come in, Blackbird.","TWN":"這裡是代號聰明男孩，黑鳥請回答。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어이, 블랙 버드 양반. 듣고 있나?! 듣고 있으면 대답을......!","JPN":"おい、ブラックバードさん、聞こえるか？　聞こえるなら回答を……！","ENG":"Hey, Blackbird. You there?! Come in if you can hear me!","TWN":"喂，黑鳥先生，你在聽嗎？！聽到的話請回答！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......듣고 있으니까 소리 좀 그만 지르게.","JPN":"……聞こえてるから、ボリュームを下げてくれんか。","ENG":"I hear you so quit shouting...","TWN":"……我在聽，小聲一點。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L48_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그리고 그냥 메이슨이라고 해. 인터넷 채팅방도 아닌데 무슨 콜 사인 타령인가?","JPN":"あと、普通にメイソンと言え。チャットでもあるまいし、何がコールサインだ。","ENG":"And just say you're Mason. What's with the call sign? What are you, some kind of a fighter pilot?","TWN":"還有你就不能直接說你是梅森嗎？還扯什麼代號，你以為是什麼網路聊天室嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"참고로 자네 콜 사인 정말 촌스러워.","JPN":"ちなみに、お前のコールサイン、最高にダサいからな。","ENG":"Plus, that call sign of yours is super tacky.","TWN":"順便說一聲，你的代號真的很土。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"스마트 가이라니, 세상에......","JPN":"スマートガイだとか、今時……","ENG":"Smart Guy? Please...","TWN":"什麼聰明男孩啊，我的天……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"난 내가 80년대로 타입슬립이라도 한 줄 알았네.","JPN":"一瞬、自分が80年代にタイムスリップしたのかと思ったよ。","ENG":"I honestly thought you traveled back in time to the 80s.","TWN":"我還以為我穿越到了80年代。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......블랙 버드도 별로 세련되어 보이진 않는데. 각자 취향은 존중하자고.","JPN":"……ブラックバードも大差はないだろ？　お互いの趣味は尊重しようぜ。","ENG":"Blackbird doesn't sound that cool, either... Let's just respect each other's taste, alright?","TWN":"……黑鳥聽起來也沒好到哪裡去，尊重一下個人喜好好嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나저나, 지금 위치가 어디지?","JPN":"それはそうと、今の位置はどこだ？","ENG":"Anyway, what's your current location?","TWN":"不說這些了，你現在在哪裡？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"상황이 많이 바뀌었어. 즉시 만나야 할 것 같아.","JPN":"状況が大きく変わったんだ。今すぐに会う必要がある。","ENG":"A lot has changed since we last talked. We need to meet up.","TWN":"情況有很大的改變，我們似乎得立刻見面才行。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그건 내가 하고 싶은 말이네.","JPN":"それはこっちのセリフさ。","ENG":"You took the words right out of my mouth.","TWN":"我也這麼覺得。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"자네, 대체 그 도시에서 무슨 짓을 하고 다닌 건가?","JPN":"お前、その都市でいったい何をしてたんだ？","ENG":"What the hell did you do to that city?","TWN":"你究竟在那座城市裡幹了什麼？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 무슨 뜻이지?","JPN":"なに？　どういう意味だ？","ENG":"Huh? What do you mean?","TWN":"什麼？這什麼意思？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"KS-1 도시관리국으로부터 자네들에 대한 체포 명령이 떨어졌네.","JPN":"KS-1都市管理局からお前らに対して逮捕命令が出されたんだ。","ENG":"The KS-1 City Managements have issued an arrest warrant for you.","TWN":"KS-1城市管理局對你發出了逮捕令。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"민간인 위협, 주요 안보시설 파괴 등, 1급 범죄 혐의야.","JPN":"民間人を脅かし、安全保障上重要な施設の破壊など、1級犯罪の疑いが持たれている。","ENG":"The charges include felonies such as threatening civilians and destroying key security facilities.","TWN":"威脅一般民眾、破壞主要安全設施等等，你已經是一級罪犯了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"현상금도 걸렸군. 액수를 보면 자네도 눈이 돌아갈걸?","JPN":"懸賞金もかけられてるな。金額を知ったら、お前も目を回すぞ。","ENG":"There's even a bounty on your head. I'm almost tempted to turn you in. It's a pretty penny...","TWN":"還有懸賞金呢，這金額你看了恐怕都會想要吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"현상금? 이런 젠장....... 그렇다는 건 설마.......","JPN":"懸賞金？　くそ、やっちまったな……それは、つまり……","ENG":"Bounty? Damn it... That probably means...","TWN":"懸賞金？混蛋……這麼說來該不會……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"맞아. 현상금에 혈안이 된 인근 용병 부대들이 지금 벌떼처럼 몰려들고 있어.","JPN":"そうだ。懸賞金に目が眩んだ近くの傭兵部隊が怒涛の勢いで押し寄せてる。","ENG":"Yeah. All the mercenaries in the area are swarming to your location for that bounty.","TWN":"沒錯，附近眼紅懸賞金的傭兵部隊正像蜜蜂一樣湧過去。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"자네 일행 중에 무장한 카운터 능력자들도 있다고 하던데.......","JPN":"お前の連れの中には武装したカウンターもいるみたいだが……","ENG":"I hear you have a few armed Counters with you?","TWN":"聽說你們一行人中還有武裝制裁者……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그것 때문에 체포가 불가피할 경우, 사살 가능 옵션도 붙어 있네.","JPN":"そのせいで逮捕できない場合は、射殺可能のオプションまでついている。","ENG":"If they can't arrest you because of those Counters, they're authorized to shoot to kill.","TWN":"所以無法逮捕你時，也可以選擇將你當場擊斃。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니, 이 자식들이 정말......","JPN":"はあ、あいつらめ……","ENG":"Those bastards...","TWN":"該死，這群混蛋真的是……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그거 아나? 메이슨.","JPN":"メイソン、お前ってやつはな。","ENG":"You know what, Mason?","TWN":"你知道嗎，梅森？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"지난번 일도 그렇고, 이번에도 그렇고, 자네 뒤탈 만드는 실력 하나는 정말 알아줘야 할 것 같아.","JPN":"前回も、今回のこともそうだ。物事をこじらせる能力だけは本当認めてやるよ。","ENG":"Remember that fiasco from last time? And now this? You sure have a knack for causing a mess.","TWN":"上次的事情也好，這次也好，我想你真的有必要了解一下自己製造麻煩的能力。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 그 자식들이 하는 말은 새빨간 거짓말이라고!","JPN":"おい、そいつらの話は真っ赤な嘘だからな！","ENG":"Hey! Everything those guys are saying is a lie!","TWN":"喂，那些傢伙說的全是謊話啊！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우린 민간인 위협 따윌 한 적이 없어!","JPN":"俺たちは民間人を脅かしたりなんかしてない！","ENG":"We've never threatened any civilians!","TWN":"我們從來沒威脅過一般民眾！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"주요 안보시설 파괴는?","JPN":"安全保障上重要な施設の破壊はどうなんだ？","ENG":"What about destroying key security facilities?","TWN":"那破壞主要安全保護設施呢？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그건...... 음...... 사소한 마찰이 좀 있긴 했지.","JPN":"それは……その……些細な衝突があったのは事実だが……","ENG":"That's... Um... There was a slight complication.","TWN":"這個……嗯……確實是有一些小小的摩擦。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......그러시겠지.","JPN":"……そうだよな。","ENG":"...Uh-huh.","TWN":"……我就知道。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하, 하여간 지금 그런 게 문제가 아니야!","JPN":"と、とにかく、そんなのは今重要じゃないんだ！","ENG":"Anyway, that's not the issue right now!","TWN":"但、但是，現在這些都不是問題！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"도시관리국도 놈들과 한패라고!","JPN":"都市管理局も奴らとグルなんだよ！","ENG":"The City Managements are colluding with them!","TWN":"城市管理局也是那些傢伙的同夥啊！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이대로 가다간 KS-1 전체가 놈들에게 넘어갈 판이야!","JPN":"このままだと、KS-1 全体が奴らの手に渡ってしまうんだ！","ENG":"They'll take over all of KS-1 at this rate!","TWN":"這樣下去整個KS-1都會落入他們手中的！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......뭐? 정말인가? 도시관리국도 넘어갔다고?","JPN":"……なに？　本当か？　都市管理局もあいつらの手に渡ったと？","ENG":"...What? Are you sure? The City Managements are in on it?","TWN":"……什麼？真的嗎？城市管理局也被他們掌控了？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래! 그러니까 당장 당신 직권으로 체포 명령이나 취소해 달라고!","JPN":"ああ！　だから、今すぐあんたの力で逮捕命令を取り下げてくれ！","ENG":"Yes! So you've got to pull some strings to cancel the arrest warrant immediately!","TWN":"沒錯！所以馬上用你的職權幫我取消逮捕命令！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"뭐? 내가 무슨 신이라도 되는 줄 아나? 그걸 어떻게 취소해?","JPN":"俺は神様か何かか？　どうやって取り下げさせろと？","ENG":"What? Do you take me for some kind of a god? How do you expect me to withdraw that?","TWN":"什麼？你以為我是什麼神仙嗎？你叫我怎麼取消啊？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭘 아닌 척하고 그러나?","JPN":"シラを切っても無駄さ。","ENG":"Don't play around.","TWN":"你有什麼好裝的？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"명색이 랭글리의 실세요원이라면 그 정도 능력은 있잖아?!","JPN":"ラングレーの実権を握ってるなら、それくらいの力はあるんだろ？","ENG":"You're one of the most powerful people in Langley! Of course you can do that!","TWN":"你好歹是蘭克利的實權要員，這種事應該在你的能力範圍內吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......이봐. 자네가 보기엔 내 목이 한 다섯 개쯤 달려 있는 줄 아나?","JPN":"……おい、もしかして俺の首がいくつもあると思ってるんじゃないだろうな？","ENG":"...Hey. I think you might be overestimating my position here...","TWN":"……喂，在你眼裡看來，我是有三個頭還是六條手臂嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"나도 그냥 공무원이라고!","JPN":"俺もただの公務員なんだよ！","ENG":"I'm just another humble civil servant!","TWN":"我也只是個公務員而已啊！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그런 정신 나간 짓을 부탁하려면 최소한 도시관리국이 배신했다는 증거라도 가져 오든가!","JPN":"そんなバカげたことを頼むなら、せめて都市管理局が裏切った証拠でも掴んでこい！","ENG":"If you want me to pull off something so outrageous, at least bring me proof that the City Managements are compromised!","TWN":"要托我做這種瘋事，至少先把城市管理局背叛的證據拿給我看！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래서 증거 배달 중이잖아?!","JPN":"ああ！　だから今、証拠をデリバリーしてるんじゃねえか！","ENG":"What do you think I'm doing right now?!","TWN":"所以我現在不正要把證據給你嗎？！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"빨리 받고 싶으면 마중이라도 좀 나오시던지!","JPN":"早く受け取りたけりゃ、迎えにでもきたらどうなんだ？","ENG":"So you'd better come quickly if you want to see what I've got!","TWN":"想快點拿到證據的話，就快點來接我啊！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"나도 바빠!","JPN":"こっちも忙しいんだよ！","ENG":"I'm busy!","TWN":"我也很忙的！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"놈들의 비밀 기지의 위치를 알아내서 이동 중이라고!","JPN":"奴らの秘密基地の位置を突き止めて、移動してるからな！","ENG":"We've located their secret base and we're on our way there!","TWN":"我剛才查到了那些傢伙的秘密基地位置，現在正在前往那邊！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 그럼 우린 어떡하라고?!","JPN":"はあ？　じゃあ、俺らはどうすればいいんだよ！？","ENG":"What? Then what are we supposed to do?!","TWN":"什麼？那我們怎麼辦啊？！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......일단 접선지 좌표를 알려 주지.","JPN":"……とりあえず、落ち合える場所の座標を送る。","ENG":"...I'll give you the coordinates for the rendezvous point.","TWN":"……總之，我先把會合點的座標告訴你。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"어떻게든 거기까지는 살아서 오라고.","JPN":"そこにたどり着くまでは、必死こいて生き延びるんだな。","ENG":"Just make sure you get there in one piece.","TWN":"然後活著到達會合點。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"체포 명령 취소는 그 후에 가져온 증거자료를 보고 이야기하도록 하지.","JPN":"逮捕命令の取り下げは、証拠資料を確認してから話してみよう。","ENG":"We'll talk about withdrawing the arrest warrant when I see the evidence.","TWN":"取消逮捕命令就等我看了你拿來的證據再說吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그럼 행운을 비네. 이만.","JPN":"それじゃ、幸運を祈る。","ENG":"Good luck. I'm out.","TWN":"那就祝你好運了，再見。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 잠깐! 어이!!","JPN":"おい、待て！　おい！！","ENG":"Hey, wait! Hey!!!","TWN":"喂，等等！喂！！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......통신 끊어졌어.","JPN":"……もう切れたよ。","ENG":"...He hung up.","TWN":"……通信被切斷了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아저씨, 아무래도 의뢰인에게 별로 신뢰를 못 받는 것 같은데?","JPN":"……おじさん、依頼人にあまり信頼されてないよね？","ENG":"It sounds like your client doesn't quite trust you...?","TWN":"……大叔，委託人好像不是很信任你耶。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 것 같군....... 유감이야.","JPN":"そのようだな……じつに残念だ。","ENG":"So it seems... It's unfortunate.","TWN":"似乎是這樣沒錯……真是遺憾。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"미나야? 대화 중에 끼어들어서 미안하지만.......","JPN":"ミナちゃん、話中に割り込んで悪いけど……","ENG":"Mina? Sorry to interrupt but...","TWN":"米娜？不好意思打斷一下你們的談話……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"저기서 뭔가 반짝거리는 게 날아오는데? 폭죽...... 같은 건 아니겠지?","JPN":"向こうから何か光るものが飛んできてるよ？　花火……とかじゃないよね？","ENG":"Something shiny is flying our way... Is it fireworks...? Probably not, right?","TWN":"那邊好像有什麼閃閃發亮的東西飛過來了耶？應該不會是……鞭炮之類的東西吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......아니! 지대지 미사일이다! 엎드려!!","JPN":"……違う！　あれは地対地ミサイルだ！　伏せろ！","ENG":"...No! It's a surface-to-surface missile! Get down!","TWN":"……不是！是地對地導彈！快趴下！！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아악!! 또 무슨 일이죠?!","JPN":"きゃああ！！　また何事ですか！？","ENG":"Eeeek! What now?!","TWN":"哇啊啊！！又怎麼了？！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"현상금 사냥꾼 놈들이다!","JPN":"賞金稼ぎの奴らだ！","ENG":"Bounty hunters!","TWN":"是賞金獵人！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하여간 평소엔 꾸물거리는 데 일가견 있는 놈들이 이런 일엔 득달같이 달려오는군.","JPN":"まったく、普段ナマケモノみてえな奴らが、こんな時だけハイエナみたいに追ってきやがって。","ENG":"These imbeciles are always dragging their feet, but they move like lightning when a bounty is involved.","TWN":"這些傢伙平時慢吞吞的，但一到這種時候就毫不猶豫，動作特別快呢。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다들 전투 준비해!","JPN":"みんな、戦闘に備えろ！","ENG":"Everyone prepare for combat!","TWN":"所有人準備戰鬥！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};